use std::error::Error;
use async_trait::async_trait;

#[async_trait]
pub trait Storage: Send + Sync {
    async fn get(&self, key: &str) -> Result<Option<String>, Box<dyn Error + Send + Sync>>;
    async fn set(&mut self, key: &str, value: &str) -> Result<(), Box<dyn Error + Send + Sync>>;
    async fn delete(&mut self, key: &str) -> Result<bool, Box<dyn Error + Send + Sync>>;
}

use super::Storage;
use async_trait::async_trait;
use std::collections::HashMap;
use std::error::Error;

pub struct MemoryStorage {
    data: HashMap<String, String>,
}

impl MemoryStorage {
    pub fn new() -> Self {
        Self { data: HashMap::new() }
    }
}

#[async_trait]
impl Storage for MemoryStorage {
    async fn get(&self, key: &str) -> Result<Option<String>, Box<dyn Error + Send + Sync>> {
        Ok(self.data.get(key).cloned())
    }

    async fn set(&mut self, key: &str, value: &str) -> Result<(), Box<dyn Error + Send + Sync>> {
        self.data.insert(key.to_string(), value.to_string());
        Ok(())
    }

    async fn delete(&mut self, key: &str) -> Result<bool, Box<dyn Error + Send + Sync>> {
        Ok(self.data.remove(key).is_some())
    }
}

use super::Storage;
use async_trait::async_trait;
use std::error::Error;
use std::path::PathBuf;
use tokio::fs;

pub struct DiskStorage {
    base_path: PathBuf,
}

impl DiskStorage {
    pub async fn new(path: &str) -> Self {
        fs::create_dir_all(path).await.unwrap();
        Self { base_path: PathBuf::from(path) }
    }

    fn key_path(&self, key: &str) -> PathBuf {
        self.base_path.join(format!("{}.dat", key))
    }
}

#[async_trait]
impl Storage for DiskStorage {
    async fn get(&self, key: &str) -> Result<Option<String>, Box<dyn Error + Send + Sync>> {
        let path = self.key_path(key);
        if path.exists() {
            Ok(Some(fs::read_to_string(path).await?))
        } else {
            Ok(None)
        }
    }

    async fn set(&mut self, key: &str, value: &str) -> Result<(), Box<dyn Error + Send + Sync>> {
        fs::write(self.key_path(key), value).await?;
        Ok(())
    }

    async fn delete(&mut self, key: &str) -> Result<bool, Box<dyn Error + Send + Sync>> {
        let path = self.key_path(key);
        if path.exists() {
            fs::remove_file(path).await?;
            Ok(true)
        } else {
            Ok(false)
        }
    }
}

