pub async fn handle_request(&mut self, method: &str, key: &str, value: Option<&str>) -> String {
    match method {
        "GET" => self.handle_get(key).await,
        "SET" => self.handle_set(key, value.unwrap_or("")).await,
        "DEL" => self.handle_delete(key).await,
        _ => "ERROR: unknown method".to_string(),
    }
}

async fn handle_get(&self, key: &str) -> String {
    match self.storage.get(key).await {
        Ok(Some(val)) => format!("OK {}", val),
        Ok(None) => "NOT_FOUND".to_string(),
        Err(e) => format!("ERROR {}", e),
    }
}

async fn handle_set(&mut self, key: &str, value: &str) -> String {
    match self.storage.set(key, value).await {
        Ok(()) => "OK".to_string(),
        Err(e) => format!("ERROR {}", e),
    }
}

async fn handle_delete(&mut self, key: &str) -> String {
    match self.storage.delete(key).await {
        Ok(true) => "OK".to_string(),
        Ok(false) => "NOT_FOUND".to_string(),
        Err(e) => format!("ERROR {}", e),
    }
}
